7: export class DefaultEventRegistry {
8:   private handlers = new Map<string, EventHandler[]>();
9:   private emitter: EventEmitter;
10: 
11:   constructor(emitter: EventEmitter) {
12:     this.emitter = emitter;
13:     this.registerDefaults();
