9: public class EventBus {
10: 
11:     private final Map<Class<? extends Event>, List<Consumer<Event>>> handlers;
12: 
13:     public EventBus() {
14:         this.handlers = new HashMap<>();
15:     }
16: 
17:     public void subscribe(Class<? extends Event> eventClass, Consumer<Event> handler) {
18:         handlers.computeIfAbsent(eventClass, k -> new ArrayList<>()).add(handler);
19:     }
20: 
21:     public void unsubscribe(Class<? extends Event> eventClass, Consumer<Event> handler) {
22:         List<Consumer<Event>> list = handlers.get(eventClass);
23:         if (list != null) {
24:             list.remove(handler);
25:         }
26:     }
27: 
28:     public void publish(Event event) {
29:         List<Consumer<Event>> list = handlers.get(event.getClass());
30:         if (list != null) {
31:             for (Consumer<Event> handler : list) {
32:                 handler.accept(event);
33:             }
34:         }
35:     }
36: 
37:     public void clear() {
38:         handlers.clear();
39:     }
40: 
